    {
        var star = i;
        <span role="button"
              class="fs-4 @(star <= (selectedRating > 0 ? selectedRating : (int)Math.Round(averageRating)) ? "text-warning" : "text-muted")"
              style="cursor: pointer;"
              @onclick="() => SubmitRating(star)"
              title="@star star(s)">
            ★
        </span>
