namespace RecipeHub.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string Description { get; set; } = "";
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple and delicious pizza with fresh mozzarella and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out the dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
            TotalRatings = 12, RatingSum = 50
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta with eggs, cheese, and pancetta.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
            Steps = ["Cook spaghetti in salted water until al dente.", "Crisp pancetta in a skillet.", "Whisk eggs with grated Pecorino and pepper.", "Toss hot pasta with pancetta, then remove from heat.", "Stir in egg mixture quickly, tossing to coat.", "Serve immediately with extra cheese."],
            TotalRatings = 8, RatingSum = 36
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken in a rich, spiced tomato cream sauce.",
            Ingredients = ["Chicken thighs", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and cooked chicken.", "Simmer 10 minutes and serve with rice."],
            TotalRatings = 15, RatingSum = 68
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Description = "Sweet, sour, and savory stir-fried rice noodles with vegetables.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Eggs"],
            Steps = ["Soak rice noodles in warm water for 30 minutes.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Stir-fry tofu until golden, set aside.", "Scramble eggs in the wok.", "Add noodles and sauce, toss until coated.", "Top with bean sprouts, peanuts, and lime wedges."],
            TotalRatings = 6, RatingSum = 25
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
            Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa.", "Serve with lime wedges."],
            TotalRatings = 10, RatingSum = 42
        },
        new()
        {
            Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Rich individual chocolate cakes with a molten center.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = ["Preheat oven to 425°F and butter ramekins.", "Melt chocolate and butter together.", "Whisk eggs, sugar, and vanilla, then fold in chocolate.", "Stir in flour gently.", "Pour into ramekins and bake 12–14 minutes.", "Invert onto plates and serve immediately."],
            TotalRatings = 20, RatingSum = 94
        },
        new()
        {
            Id = 7, Title = "Greek Salad", Category = "Mediterranean",
            Description = "A refreshing salad with crisp vegetables and tangy feta.",
            Ingredients = ["Cucumber", "Tomatoes", "Red onion", "Kalamata olives", "Feta cheese", "Olive oil", "Oregano", "Lemon juice"],
            Steps = ["Chop cucumber, tomatoes, and red onion.", "Combine vegetables in a large bowl.", "Add olives and crumbled feta.", "Drizzle with olive oil and lemon juice.", "Sprinkle with oregano.", "Toss gently and serve."],
            TotalRatings = 5, RatingSum = 21
        },
        new()
        {
            Id = 8, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh and creamy avocado dip with lime and cilantro.",
            Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Salt", "Tomato"],
            Steps = ["Halve and pit avocados, scoop into a bowl.", "Mash to desired consistency.", "Stir in lime juice, diced onion, and jalapeño.", "Fold in chopped cilantro and tomato.", "Season with salt.", "Serve with tortilla chips."],
            TotalRatings = 7, RatingSum = 30
        },
    ];

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public List<Recipe> GetAll() => _recipes;

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}

