toolArgs.file_text:
@page "/recipes/{Category}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@Category Recipes — RecipeHub</PageTitle>

<h1>
    @(Category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🍜",
        "Mexican" => "🌮",
        "Desserts" => "🍫",
        "Mediterranean" => "🥗",
        _ => "🍽️"
    })
    @Category Recipes
</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                            </span>
                            <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string Category { get; set; } = "";
    private List<RecipeHub.Services.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-5">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-7">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">📋 Steps</h5></div>
                <ol class="list-group list-group-numbered list-group-flush">
                    @foreach (var step in recipe.Steps)
                    {
                        <li class="list-group-item">@step</li>
                    }
                </ol>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private RecipeHub.Services.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@inject RecipeHub.Services.RecipeService RecipeService

<div class="my-3">
    <span class="me-2"><strong>Rate this recipe:</strong></span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              class="fs-4 @(star <= (selectedRating > 0 ? selectedRating : (int)Math.Round(averageRating)) ? "text-warning" : "text-muted")"
              style="cursor: pointer;"
              @onclick="() => SubmitRating(star)"
              title="@star star(s)">
            ★
        </span>
    }
    <span class="ms-2 text-muted">
        @if (hasRated)
        {
            <span>Thanks! You rated @selectedRating star(s). </span>
        }
        @averageRating.ToString("0.0") avg (@totalRatings ratings)
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int selectedRating;
    private bool hasRated;
    private double averageRating;
    private int totalRatings;

    protected override void OnParametersSet()
    {
        LoadRating();
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        selectedRating = stars;
        hasRated = true;
        LoadRating();
    }

    private void LoadRating()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            averageRating = recipe.AverageRating;
            totalRatings = recipe.TotalRatings;
        }
    }
}

